import scala.xml.XML

class ConfigurationService {
  def parseConfiguration(configXml: String): Map[String, Any] = {
    val xml = XML.loadString(configXml)
    // Prevent XXE attacks by disabling entity resolution
    xml.withResolveExternalEntities(false).map { node =>
      (node \ "@name").text -> node.text
    }.toMap
  }
}